22	template<typename T>
23	__global__ void logProbAddCumLogProb(float*       log_probs,
24	                                     const T*     logits,
25	                                     const float* cum_log_probs,
26	                                     const int*   end_ids,
27	                                     const bool*  finished,
28	                                     const int    beam_width,
29	                                     const int    n)
30	{
31	    int  bid    = blockIdx.x;
32	    bool finish = finished != nullptr ? finished[bid] : false;
33	    int  offset = bid * n;
34	
35	    float            max_val = -1 * FLT_MAX;
36	    __shared__ float s_max_val;
37	    __shared__ float s_sum_val;
38	
39	    if (finish) {
40	        for (int tid = threadIdx.x; tid < n; tid += blockDim.x) {
41	            log_probs[offset + tid] = (tid == end_ids[bid / beam_width]) ? cum_log_probs[bid] : -FLT_MAX;
42	        }
43	    }
44	    else {
45	        for (int tid = threadIdx.x; tid < n; tid += blockDim.x) {
46	            log_probs[offset + tid] = (float)(logits[offset + tid]);
47	            max_val                 = max(max_val, log_probs[offset + tid]);
48	        }
49	
50	        max_val = blockReduceMax(max_val);
51	        if (threadIdx.x == 0) {
52	            s_max_val = max_val;
53	        }
54	        __syncthreads();
55	
56	        float sum_val = 0.0f;
57	        for (int tid = threadIdx.x; tid < n; tid += blockDim.x) {
58	            log_probs[offset + tid] = __expf(log_probs[offset + tid] - s_max_val);
59	            sum_val += log_probs[offset + tid];
60	        }
61	
62	        sum_val = blockReduceSum(sum_val);
63	        if (threadIdx.x == 0) {
64	            s_sum_val = sum_val + 1e-6f;
65	        }
66	        __syncthreads();
67	
68	        for (int tid = threadIdx.x; tid < n; tid += blockDim.x) {
69	            log_probs[offset + tid] = logf(log_probs[offset + tid] / s_sum_val) + cum_log_probs[bid];
70	        }
71	    }
72	}
73	
74	template<typename T>
75	void invokeLogProbAddCumLogProb(float*       log_probs,
76	                                const T*     logits,
77	                                const float* cum_log_probs,
78	                                const int*   end_ids,
79	                                const bool*  finished,
80	                                const int    m,
81	                                const int    beam_width,
82	                                const int    n,
83	                                cudaStream_t stream)
84	{
85	    dim3 grid(m);
86	    dim3 block(min(n, 1024));
87	    /*n is the vocab_size, e.g., 30000, 7000.... vocab_size is usually very big. */
88	    logProbAddCumLogProb<<<grid, block, 0, stream>>>(
89	        log_probs, logits, cum_log_probs, end_ids, finished, beam_width, n);
90	}
91	
92	template<typename T>
93	__global__ void updateStatesKernel(T*             log_probs,
94	                                   T*             cum_log_probs,
95	                                   float*         output_log_probs,
96	                                   bool*          finished,
97	                                   int*           parent_ids,
98	                                   int*           sequence_length,
99	                                   int*           word_ids,
100	                                   int*           output_ids,
101	                                   BeamHypotheses beam_hyps,
102	                                   const int      local_batch_size,
103	                                   const int      beam_width,
104	                                   const int      vocab_size,
105	                                   const int*     end_ids)
106	{
107	    for (int index = blockIdx.x * blockDim.x + threadIdx.x; index < local_batch_size * beam_width;
108	         index += blockDim.x * gridDim.x) {
109	
110	        int batch_id           = index / beam_width;
111	        sequence_length[index] = finished[index] ? sequence_length[index] : sequence_length[index] + 1;
112	
113	        int beam_id = (word_ids[index] / vocab_size) % beam_width;
114	        int word_id = word_ids[index] % vocab_size;
115	
116	        if (output_log_probs != nullptr) {
117	            // get the cum_log_probs of previous run
118	            output_log_probs[index] = log_probs[batch_id * beam_width * vocab_size + beam_id * vocab_size + word_id]
119	                                      - cum_log_probs[batch_id * beam_width + beam_id];
120	        }
121	        cum_log_probs[index]   = log_probs[batch_id * beam_width * vocab_size + beam_id * vocab_size + word_id];
122	        sequence_length[index] = sequence_length[batch_id * beam_width + beam_id];
123	        finished[index]        = word_id == end_ids[batch_id] ? 1 : 0;
124	        parent_ids[index]      = beam_id;
125	        word_ids[index]        = word_id;
126	        output_ids[index]      = word_id;
127	
128	        if (beam_hyps.num_beams != nullptr) {
129	            if (beam_hyps.num_beams[beam_hyps.ite * beam_hyps.local_batch_size + batch_id] == beam_width) {
130	                for (int i = 0; i < beam_width; i++) {
131	                    finished[batch_id * beam_width + i] = true;
132	                }
133	            }
134	        }
135	    }
136	}
137	
138	void invokeUpdateStates(float*          log_probs,
139	                        float*          cum_log_probs,
140	                        float*          output_log_probs,
141	                        bool*           finished,
142	                        int*            parent_ids,
143	                        int*            sequence_length,
144	                        int*            word_ids,
145	                        int*            output_ids,
146	                        BeamHypotheses* beam_hyps,
147	                        const int       local_batch_size,
148	                        const int       beam_width,
149	                        const int       vocab_size,
150	                        const int*      end_ids,
151	                        cudaStream_t    stream)
152	{
153	    dim3 grid((int)ceil(local_batch_size * beam_width * 1.0 / 256));
154	    dim3 block(256);
155	
156	    updateStatesKernel<float><<<grid, block, 0, stream>>>(log_probs,
157	                                                          cum_log_probs,
158	                                                          output_log_probs,
159	                                                          finished,
160	                                                          parent_ids,
161	                                                          sequence_length,
162	                                                          word_ids,
163	                                                          output_ids,
164	                                                          *beam_hyps,
165	                                                          local_batch_size,
166	                                                          beam_width,
167	                                                          vocab_size,
168	                                                          end_ids);
169	}
