171	template<typename T>
172	void BeamSearchLayer<T>::invokeSoftMax(TensorMap* output_tensors, TensorMap* input_tensors)
173	{
174	    // input_tensors:
175	    //      logits [local_batch_size, beam_width, vocab_size_padded]
176	    //      embedding_bias [vocab_size_padded]
177	    //      step [1] on cpu
178	    //      src_cache_indirection [local_batch_size, beam_width, max_seq_len]
179	    //      max_input_length [1] on cpu
180	    //      input_lengths [local_batch_size * beam_width]
181	    //      ite [1] on cpu
182	    //      beam_search_diversity_rate [1] on cpu, optional
183	    //      temperature [1] on cpu, optional
184	    //      len_penalty [1] on cpu, optional
185	    //      repetition_penalty [1] on cpu, optional
186	
187	    // output_tensors:
188	    //      output_ids [max_seq_len, batch_size, beam_width]
189	    //      finished [local_batch_size * beam_width]
190	    //      cum_log_probs [local_batch_size * beam_width]
191	    //      parent_ids [max_seq_len, batch_size * beam_width]
192	    //      sequence_length [local_batch_size * beam_width]
193	    //      tgt_cache_indirection [local_batch_size, beam_width, max_seq_len]
194	    //      output_log_probs [max_seq_len, batch_size * beam_width], optional
195	    //      beam_hyps, optional
196	
197	    FT_CHECK(input_tensors->size() >= 7);
198	    FT_CHECK(output_tensors->size() >= 6);
199	
200	    const int   batch_size       = output_tensors->at("output_ids").shape[1];
201	    const int   beam_width       = output_tensors->at("output_ids").shape[2];
202	    const int   step             = input_tensors->at("step").getVal<int>();
203	    const int   ite              = input_tensors->at("ite").getVal<int>();
204	    const int   local_batch_size = input_tensors->at("logits").shape[0];
205	    const float diversity_rate   = input_tensors->isExist("beam_search_diversity_rate") ?
206	                                       input_tensors->at("beam_search_diversity_rate").getVal<float>() :
207	                                       0.0f;
208	    const float length_penalty =
209	        input_tensors->isExist("len_penalty") ? input_tensors->at("len_penalty").getVal<float>() : 0.0f;
210	
211	    const int id_offset = step * batch_size * beam_width + ite * local_batch_size * beam_width;
212	    invokeLogProbAddCumLogProb(float_log_prob_buf_,
213	                               input_tensors->at("logits").getPtr<T>(),
214	                               output_tensors->at("cum_log_probs").getPtr<float>(),
215	                               input_tensors->at("end_id").getPtr<const int>(),
216	                               output_tensors->at("finished").getPtr<bool>(),
217	                               local_batch_size * beam_width,
218	                               beam_width,
219	                               vocab_size_padded_,
220	                               stream_);
221	    sync_check_cuda_error();
222	
223	    BeamHypotheses beam_hyps;
224	    if (output_tensors->isExist("beam_hyps") && diversity_rate == 0.0f) {
225	        beam_hyps                      = *((BeamHypotheses*)(output_tensors->at("beam_hyps").getPtr<void>()));
226	        beam_hyps.step                 = step;
227	        beam_hyps.ite                  = ite;
228	        beam_hyps.local_batch_size     = local_batch_size;
229	        beam_hyps.batch_size           = output_tensors->at("output_ids").shape[1];
230	        beam_hyps.max_seq_len          = output_tensors->at("output_ids").shape[0];
231	        beam_hyps.output_ids_src       = output_tensors->at("output_ids").getPtr<int>();
232	        beam_hyps.parent_ids_src       = output_tensors->at("parent_ids").getPtr<int>();
233	        beam_hyps.sequence_lengths_src = output_tensors->at("sequence_length").getPtr<int>();
234	        beam_hyps.length_penalty       = length_penalty;
235	    }
236	
237	    invokeTopkBeamSearch<float>(topk_softmax_workspace_,
238	                                topk_softmax_workspace_size_,
239	                                float_log_prob_buf_,
240	                                output_tensors->at("output_ids").getPtrWithOffset<int>(id_offset),
241	                                &beam_hyps,
242	                                output_tensors->at("finished").getPtr<bool>(),
243	                                output_tensors->isExist("sequence_length") ?
244	                                    output_tensors->at("sequence_length").getPtr<int>() :
245	                                    (int*)nullptr,
246	                                local_batch_size,
247	                                beam_width,
248	                                vocab_size_padded_,
249	                                diversity_rate,
250	                                length_penalty,
251	                                input_tensors->at("end_id").getPtr<const int>(),
252	                                stream_);
253	    sync_check_cuda_error();
254	
255	    invokeUpdateStates(float_log_prob_buf_,
256	                       output_tensors->at("cum_log_probs").getPtr<float>(),
257	                       output_tensors->getPtrWithOffset<float>("output_log_probs", id_offset, nullptr),
258	                       output_tensors->at("finished").getPtr<bool>(),
259	                       output_tensors->at("parent_ids").getPtrWithOffset<int>(id_offset),
260	                       output_tensors->at("sequence_length").getPtr<int>(),
261	                       output_tensors->at("output_ids").getPtrWithOffset<int>(id_offset),
262	                       output_tensors->at("output_ids").getPtrWithOffset<int>(id_offset),
263	                       &beam_hyps,
264	                       local_batch_size,
265	                       beam_width,
266	                       vocab_size_padded_,
267	                       input_tensors->at("end_id").getPtr<const int>(),
268	                       stream_);
269	    sync_check_cuda_error();
270	}
271	
272	template<typename T>
273	void BeamSearchLayer<T>::allocateBuffer()
274	{
275	    FT_CHECK(false);
276	}
277	
278	template<typename T>
279	void BeamSearchLayer<T>::allocateBuffer(size_t batch_size, size_t beam_width)
280	{
281	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
282	
283	    invokeTopkBeamSearch<float>(nullptr,
284	                                topk_softmax_workspace_size_,
285	                                nullptr,
286	                                nullptr,
287	                                nullptr,
288	                                nullptr,
289	                                nullptr,
290	                                batch_size,
291	                                beam_width,
292	                                vocab_size_padded_,
293	                                0.0f,  // diversity rate
294	                                0.0f,  // length penalty
295	                                nullptr,
296	                                stream_);
297	    topk_softmax_workspace_ = reinterpret_cast<float*>(allocator_->reMalloc(
298	        topk_softmax_workspace_,
299	        topk_softmax_workspace_size_ + sizeof(float) * batch_size * beam_width * vocab_size_padded_,
300	        false));
301	    float_log_prob_buf_     = (float*)((char*)topk_softmax_workspace_ + topk_softmax_workspace_size_);
302	    is_allocate_buffer_     = true;
303	}
304	
305	template<typename T>
306	BeamSearchLayer<T>::BeamSearchLayer(size_t           max_batch_size,
307	                                    size_t           head_num,
308	                                    size_t           size_per_head,
309	                                    size_t           beam_width,
310	                                    size_t           vocab_size,
311	                                    size_t           vocab_size_padded,
312	                                    int              end_id,
313	                                    float            diversity_rate,
314	                                    float            temperature,
315	                                    float            len_penalty,
316	                                    float            repetition_penalty,
317	                                    cudaStream_t     stream,
318	                                    cublasMMWrapper* cublas_wrapper,
319	                                    IAllocator*      allocator,
320	                                    bool             is_free_buffer_after_forward):
321	    BaseBeamSearchLayer<T>(max_batch_size,
322	                           head_num,
323	                           size_per_head,
324	                           beam_width,
325	                           vocab_size,
326	                           vocab_size_padded,
327	                           end_id,
328	                           diversity_rate,
329	                           temperature,
330	                           len_penalty,
331	                           repetition_penalty,
332	                           stream,
333	                           cublas_wrapper,
334	                           allocator,
335	                           is_free_buffer_after_forward)
336	{
337	}
338	
339	template<typename T>
340	BeamSearchLayer<T>::BeamSearchLayer(BeamSearchLayer<T> const& beam_search_layer):
341	    BaseBeamSearchLayer<T>(beam_search_layer)
342	{
343	}
344	
345	template<typename T>
346	BeamSearchLayer<T>::~BeamSearchLayer()
347	{
348	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
349	}
350	
351	template class BeamSearchLayer<float>;
352	template class BeamSearchLayer<half>;
353	
354	}  // namespace fastertransformer
