33	template<typename T>
34	__device__ __forceinline__ T apply_length_penalty(T log_prob, int length, float length_penalty)
35	{
36	    // score = log(prob) / (length)^length_penalty.
37	    if (length_penalty == 0.0f || length == 1) {
38	        return log_prob;
39	    }
40	    return log_prob / static_cast<T>(powf((float)length, length_penalty));
41	}
42	
43	template<typename T, int MAX_K, int THREADBLOCK_SIZE>
44	__launch_bounds__(THREADBLOCK_SIZE) __global__ void beam_topK_kernel(const T*    log_probs,
45	                                                                     int*        topk_tmp_id_buf,
46	                                                                     T*          topk_tmp_val_buf,
47	                                                                     const bool* finished,
48	                                                                     const int*  sequence_lengths,
49	                                                                     const int   vocab_size,
50	                                                                     T           diversity_rate,
51	                                                                     float       length_penalty)
52	{
53	    typedef cub::BlockReduce<TopK<T, MAX_K>, THREADBLOCK_SIZE> BlockReduce;
54	    __shared__ typename BlockReduce::TempStorage               temp_storage;
55	
56	    int            thread_id = threadIdx.x;
57	    int            block_id  = blockIdx.x;  // batch beam index.
58	    TopK<T, MAX_K> partial;
59	
60	    const bool IS_FP16   = std::is_same<T, half>::value;
61	    const T    MAX_T_VAL = (IS_FP16) ? HALF_FLT_MAX : FLT_MAX;
62	
63	#pragma unroll
64	    for (int i = 0; i < MAX_K; ++i) {
65	        partial.p[i] = -1;
66	        partial.u[i] = -MAX_T_VAL;
67	    }
68	
69	#pragma unroll
70	    for (int elem_id = thread_id; elem_id < vocab_size; elem_id += THREADBLOCK_SIZE) {
71	        int index = elem_id + block_id * vocab_size;
72	        T   score = length_penalty == 0.0f ? log_probs[index] :
73	                                             apply_length_penalty(log_probs[index],
74	                                                                finished[block_id] ? sequence_lengths[block_id] :
75	                                                                                       sequence_lengths[block_id] + 1,
76	                                                                length_penalty);
77	        partial.insert(score, index);
78	    }
79	
80	    TopK<T, MAX_K> total = BlockReduce(temp_storage).Reduce(partial, reduce_topk_op<T, MAX_K>);
81	
82	    if (thread_id == 0) {
83	        int index = block_id * MAX_K;
84	
85	#pragma unroll
86	        for (int i = 0; i < MAX_K; ++i) {
87	            topk_tmp_id_buf[index + i]  = total.p[i];
88	            topk_tmp_val_buf[index + i] = total.u[i] + diversity_rate * (T)i;
89	        }
90	    }
91	}
92	
93	template<typename T, int MAX_K, int THREADBLOCK_SIZE>
94	__launch_bounds__(THREADBLOCK_SIZE) __global__
95	    void batch_topK_kernel(int* topk_tmp_id_buf, T* topk_tmp_val_buf, int* id_buf)
96	{
97	    int            thread_id = threadIdx.x;
98	    int            block_id  = blockIdx.x;
99	    const bool     IS_FP16   = std::is_same<T, half>::value;
100	    const T        MAX_T_VAL = (IS_FP16) ? HALF_FLT_MAX : FLT_MAX;
101	    TopK<T, MAX_K> partial;
102	    if (thread_id == 0) {
103	        for (int i = 0; i < MAX_K; ++i) {
104	            partial.p[i] = -1;
105	            partial.u[i] = -MAX_T_VAL;
106	        }
107	
108	        int index = block_id * MAX_K * MAX_K;
109	        for (int i = 0; i < MAX_K * MAX_K; i++) {
110	            partial.insert((T)topk_tmp_val_buf[index + i], topk_tmp_id_buf[index + i]);
111	        }
112	
113	        index = block_id * MAX_K;
114	        for (int i = 0; i < MAX_K; i++) {
115	            id_buf[index + i] = partial.p[i];
116	        }
117	    }
118	}
