120	template<typename T, int MAX_K, int THREADBLOCK_SIZE>
121	__launch_bounds__(THREADBLOCK_SIZE) __global__
122	    void batch_topK_kernel_v2(int* topk_tmp_id_buf, T* topk_tmp_val_buf, int* id_buf)
123	{
124	    typedef cub::BlockReduce<TopK<T, MAX_K>, THREADBLOCK_SIZE> BlockReduce;
125	    __shared__ typename BlockReduce::TempStorage               temp_storage;
126	
127	    int            tid = threadIdx.x;
128	    int            bid = blockIdx.x;
129	    TopK<T, MAX_K> partial;
130	    const bool     IS_FP16   = std::is_same<T, half>::value;
131	    const T        MAX_T_VAL = (IS_FP16) ? HALF_FLT_MAX : FLT_MAX;
132	
133	#pragma unroll
134	    for (int i = 0; i < MAX_K; ++i) {
135	        partial.p[i] = -1;
136	        partial.u[i] = -MAX_T_VAL;
137	    }
138	
139	    int ite = MAX_K * MAX_K / THREADBLOCK_SIZE;
140	#pragma unroll
141	    for (int i = 0; i < ite; i++) {
142	        int index = bid * MAX_K * MAX_K + i * THREADBLOCK_SIZE + tid;
143	        partial.insert((T)topk_tmp_val_buf[index], topk_tmp_id_buf[index]);
144	    }
145	
146	    TopK<T, MAX_K> total = BlockReduce(temp_storage).Reduce(partial, reduce_topk_op<T, MAX_K>);
147	
148	    if (tid == 0) {
149	#pragma unroll
150	        for (int i = 0; i < MAX_K; i++) {
151	            id_buf[bid * MAX_K + i] = total.p[i];
152	        }
153	    }
154	}
155	
156	template<typename T, int BLOCK_SIZE_, int BLOCKS_PER_BEAM_>
157	__global__ void topk_stage_1_opt3(const T* __restrict log_probs,
158	                                  T*          tmp_log_probs,
159	                                  int*        topk_tmp_id_buf,
160	                                  T*          topk_tmp_val_buf,
161	                                  const bool* finished,
162	                                  const int*  sequence_lengths,
163	                                  const int   k,
164	                                  const int   vocab_size,
165	                                  const float length_penalty,
166	                                  const int*  end_ids)
167	{
168	    typedef cub::BlockReduce<TopK_2<T>, BLOCK_SIZE_> BlockReduce;
169	    __shared__ typename BlockReduce::TempStorage     temp_storage;
170	
171	    const int tid = threadIdx.x;
172	    const int bid = blockIdx.x;
173	
174	    const int  row_id             = bid / BLOCKS_PER_BEAM_;  // row id for log_probs (batchbeam index)
175	    const int  block_lane         = bid % BLOCKS_PER_BEAM_;  // block id for a beam
176	    const int  tmp_log_buf_index  = row_id * vocab_size;
177	    const int  tmp_topk_buf_index = row_id * BLOCKS_PER_BEAM_ * k + block_lane * k;
178	    TopK_2<T>  partial;
179	    const bool IS_FP16   = std::is_same<T, half>::value;
180	    const T    MAX_T_VAL = (IS_FP16) ? HALF_FLT_MAX : FLT_MAX;
181	
182	    if (finished != nullptr && finished[row_id] == true) {
183	        if (tid < k) {
184	            const int index = tmp_topk_buf_index + tid;
185	            if (block_lane == 0 && tid == 0) {
186	                const int end_id        = end_ids[row_id / k];
187	                topk_tmp_id_buf[index]  = tmp_log_buf_index + end_id;
188	                topk_tmp_val_buf[index] = log_probs[tmp_log_buf_index + end_id];
189	            }
190	            else {
191	                topk_tmp_id_buf[index]  = -1;
192	                topk_tmp_val_buf[index] = -MAX_T_VAL;
193	            }
194	        }
195	        return;
196	    }
197	
198	    for (int elem_id = tid + block_lane * BLOCK_SIZE_; elem_id < vocab_size;
199	         elem_id += BLOCK_SIZE_ * BLOCKS_PER_BEAM_) {
200	        int index            = elem_id + tmp_log_buf_index;
201	        tmp_log_probs[index] = log_probs[index];
202	    }
203	
204	    for (int ite = 0; ite < k; ite++) {
205	        partial.init();
206	#pragma unroll
207	        for (int elem_id = tid + block_lane * BLOCK_SIZE_; elem_id < vocab_size;
208	             elem_id += BLOCK_SIZE_ * BLOCKS_PER_BEAM_) {
209	            int index = elem_id + tmp_log_buf_index;
210	            partial.insert(tmp_log_probs[index], index);
211	        }
212	
213	        TopK_2<T> total = BlockReduce(temp_storage).Reduce(partial, reduce_topk_op_2<T>);
214	
215	        if (tid == 0) {
216	            const int index         = tmp_topk_buf_index + ite;
217	            topk_tmp_id_buf[index]  = total.p;
218	            topk_tmp_val_buf[index] = total.u;
219	            tmp_log_probs[total.p]  = -MAX_T_VAL;
220	        }
221	        __syncthreads();
222	    }
223	}
224	
225	template<typename T, int BLOCK_SIZE_, int BLOCKS_PER_BEAM_>
226	__global__ void topk_stage_2_opt3(const int* __restrict topk_tmp_id_buf,
227	                                  T*             topk_tmp_val_buf,
228	                                  int*           ids,
229	                                  BeamHypotheses beam_hyps,
230	                                  const int*     end_ids,
231	                                  const int      vocab_size,
232	                                  const int      k)
233	{
234	    const int  size      = k * k * BLOCKS_PER_BEAM_;
235	    const int  tid       = threadIdx.x;
236	    const int  batch_id  = blockIdx.x;
237	    const bool IS_FP16   = std::is_same<T, half>::value;
238	    const T    MAX_T_VAL = (IS_FP16) ? HALF_FLT_MAX : FLT_MAX;
239	
240	    typedef cub::BlockReduce<TopK_2<T>, BLOCK_SIZE_> BlockReduce;
241	    __shared__ typename BlockReduce::TempStorage     temp_storage;
242	    extern __shared__ char                           array[];
243	    T*                                               s_val = topk_tmp_val_buf + batch_id * size;
244	    int*                                             s_id  = (int*)(array);
245	
246	    __shared__ int  selected_beams;
247	    __shared__ bool is_stop;
248	
249	    if (tid == 0) {
250	        selected_beams = 0;
251	        is_stop        = false;
252	    }
253	    __syncthreads();
254	    if (beam_hyps.num_beams != nullptr) {
255	        const int global_batch_idx = beam_hyps.ite * beam_hyps.local_batch_size + batch_id;
256	        if (beam_hyps.num_beams[global_batch_idx] == 0 && tid == 0) {
257	            // initialize the buffer
258	            beam_hyps.min_normed_scores[global_batch_idx] = FLT_MAX;
259	        }
260	        else if (beam_hyps.num_beams[global_batch_idx] == k) {
261	            return;
262	        }
263	    }
264	
265	    TopK_2<T> partial;
266	
267	    // In some cases, we may encounter k finished sentences, but scores are bad. So, the max iteration
268	    // is 2*k here
269	    for (int ite = 0; ite < 2 * k; ite++) {
270	        partial.init();
271	#pragma unroll
272	        for (int i = tid; i < size; i += BLOCK_SIZE_) {
273	            partial.insert(s_val[i], i);
274	        }
275	
276	        TopK_2<T> total = BlockReduce(temp_storage).Reduce(partial, reduce_topk_op_2<T>);
277	
278	        if (tid == 0) {
279	            if (beam_hyps.num_beams != nullptr
280	                && topk_tmp_id_buf[batch_id * size + total.p] % vocab_size == end_ids[batch_id]) {
281	                // if beam_token does not belong to top num_beams tokens, it should not be added. Refer from
282	                // https://github.com/huggingface/transformers/blob/v4.24.0/src/transformers/generation_beam_search.py#L257
283	                if (ite >= k) {
284	                    s_val[total.p] = -MAX_T_VAL;
285	                }
286	                else {
287	                    const int   global_batch_idx = beam_hyps.ite * beam_hyps.local_batch_size + batch_id;
288	                    const float normed_score =
289	                        apply_length_penalty(s_val[total.p], beam_hyps.step, beam_hyps.length_penalty);
290	                    const int num_beam = beam_hyps.num_beams[global_batch_idx];
291	                    int       beam_idx = num_beam;
292	                    // If there are beam_width finished sentences, check that the score of selected candidatet
293	                    // is higher than min_normed_score or not. If current score is better, replace worst one
294	                    // and update the min_normed_score.
295	                    if (num_beam == k) {
296	                        if (normed_score < beam_hyps.min_normed_scores[global_batch_idx]) {
297	                            // end the tracing and exist this for loop
298	                            selected_beams = k;
299	                            is_stop        = true;
300	                            break;
301	                        }
302	                        else {
303	                            // find the beam index which's score = min_normed_score, erase it.
304	                            for (int j = 0; j < k; j++) {
305	                                if (beam_hyps.normed_scores[global_batch_idx * k + j]
306	                                    == beam_hyps.min_normed_scores[global_batch_idx]) {
307	                                    beam_idx = j;
308	                                    beam_hyps.num_beams[global_batch_idx]--;
309	
310	                                    beam_hyps.min_normed_scores[global_batch_idx]     = FLT_MAX;
311	                                    beam_hyps.normed_scores[global_batch_idx * k + j] = normed_score;
312	                                    for (int l = 0; l < k; l++) {
313	                                        beam_hyps.min_normed_scores[global_batch_idx] =
314	                                            min(beam_hyps.min_normed_scores[global_batch_idx],
315	                                                beam_hyps.normed_scores[global_batch_idx * k + l]);
316	                                    }
317	                                    break;
318	                                }
319	                            }
320	                        }
321	                    }
322	                    const int tgt_id_offset = ((batch_id + beam_hyps.ite * beam_hyps.local_batch_size) * k + beam_idx)
323	                                              * (beam_hyps.max_seq_len);
324	                    beam_hyps.output_ids_tgt[tgt_id_offset + beam_hyps.step] = end_ids[batch_id];
325	
326	                    int prev_id = (topk_tmp_id_buf[batch_id * size + total.p] / vocab_size) % k;
327	                    for (int j = beam_hyps.step - 1; j >= 0; j--) {
328	                        const int src_idx = j * beam_hyps.batch_size * k
329	                                            + beam_hyps.ite * beam_hyps.local_batch_size * k + batch_id * k + prev_id;
330	
331	                        beam_hyps.output_ids_tgt[tgt_id_offset + j] = beam_hyps.output_ids_src[src_idx];
332	                        prev_id                                     = beam_hyps.parent_ids_src[src_idx];
333	                    }
334	                    const int tgt_beam_idx                       = global_batch_idx * k + beam_idx;
335	                    beam_hyps.sequence_lengths_tgt[tgt_beam_idx] = beam_hyps.step;
336	                    beam_hyps.normed_scores[tgt_beam_idx]        = normed_score;
337	                    beam_hyps.min_normed_scores[global_batch_idx] =
338	                        min(beam_hyps.min_normed_scores[global_batch_idx], beam_hyps.normed_scores[tgt_beam_idx]);
339	
340	                    s_val[total.p] = -MAX_T_VAL;
341	
342	                    beam_hyps.num_beams[global_batch_idx]++;
343	                }
344	            }
345	            else {
346	                s_id[selected_beams] = total.p;
347	                s_val[total.p]       = -MAX_T_VAL;
348	                selected_beams++;
349	            }
350	        }
351	        __syncthreads();
352	        if (selected_beams >= k) {
353	            break;
354	        }
355	    }
356	    if (tid < k && is_stop == false) {
357	        ids[batch_id * k + tid] = topk_tmp_id_buf[batch_id * size + s_id[tid]];
358	    }
359	}
360	
361	template<typename T, int BLOCK_SIZE, int BLOCKS_PER_BEAM>
362	__global__ void topk_stage_1_opt2_general(const T* __restrict log_probs,
363	                                          T*          tmp_log_probs,
364	                                          int*        topk_tmp_id_buf,
365	                                          T*          topk_tmp_val_buf,
366	                                          const bool* finished,
367	                                          const int*  sequence_lengths,
368	                                          const int   k,
369	                                          const int   vocab_size,
370	                                          const float length_penalty)
371	{
372	    const bool                                      IS_FP16   = std::is_same<T, half>::value;
373	    const T                                         MAX_T_VAL = (IS_FP16) ? HALF_FLT_MAX : FLT_MAX;
374	    typedef cub::BlockReduce<TopK_2<T>, BLOCK_SIZE> BlockReduce;
375	    __shared__ typename BlockReduce::TempStorage    temp_storage;
376	
377	    const int tid                = threadIdx.x;
378	    const int bid                = blockIdx.x;
379	    const int row_id             = bid / BLOCKS_PER_BEAM;  // row id for log_probs
380	    const int block_lane         = bid % BLOCKS_PER_BEAM;  // block id for a beam
381	    const int tmp_log_buf_index  = row_id * vocab_size;
382	    const int tmp_topk_buf_index = row_id * BLOCKS_PER_BEAM * k + block_lane * k;
383	    TopK_2<T> partial;
384	
385	    for (int elem_id = tid + block_lane * BLOCK_SIZE; elem_id < vocab_size; elem_id += BLOCK_SIZE * BLOCKS_PER_BEAM) {
386	        int index            = elem_id + tmp_log_buf_index;
387	        tmp_log_probs[index] = log_probs[index];
388	    }
389	
390	    for (int ite = 0; ite < k; ite++) {
391	        partial.init();
392	#pragma unroll
393	        for (int elem_id = tid + block_lane * BLOCK_SIZE; elem_id < vocab_size;
394	             elem_id += BLOCK_SIZE * BLOCKS_PER_BEAM) {
395	            int index = elem_id + tmp_log_buf_index;
396	            partial.insert(tmp_log_probs[index], index);
397	        }
398	
399	        TopK_2<T> total = BlockReduce(temp_storage).Reduce(partial, reduce_topk_op_2<T>);
400	
401	        if (tid == 0) {
402	            const int index         = tmp_topk_buf_index + ite;
403	            topk_tmp_id_buf[index]  = total.p;
404	            topk_tmp_val_buf[index] = total.u;
405	            tmp_log_probs[total.p]  = -MAX_T_VAL;
406	        }
407	        __syncthreads();
408	    }
409	}
410	
411	template<typename T, int BLOCK_SIZE, int BLOCKS_PER_BEAM>
412	__global__ void topk_stage_2_opt2_general(const int* __restrict topk_tmp_id_buf,
413	                                          T*             topk_tmp_val_buf,
414	                                          int*           ids,
415	                                          BeamHypotheses beam_hyps,
416	                                          const int*     end_ids,
417	                                          const int      k,
418	                                          const int      vocab_size)
419	{
420	    const int  size      = k * k * BLOCKS_PER_BEAM;
421	    const int  tid       = threadIdx.x;
422	    const int  batch_id  = blockIdx.x;
423	    const bool IS_FP16   = std::is_same<T, half>::value;
424	    const T    MAX_T_VAL = (IS_FP16) ? HALF_FLT_MAX : FLT_MAX;
425	
426	    typedef cub::BlockReduce<TopK_2<T>, BLOCK_SIZE> BlockReduce;
427	    __shared__ typename BlockReduce::TempStorage    temp_storage;
428	    extern __shared__ char                          array[];
429	    T*                                              s_val = topk_tmp_val_buf + batch_id * size;
430	    int*                                            s_id  = (int*)(array);
431	
432	    __shared__ int  selected_beams;
433	    __shared__ bool is_stop;
434	
435	    if (tid == 0) {
436	        selected_beams = 0;
437	        is_stop        = false;
438	    }
439	    __syncthreads();
440	    if (beam_hyps.num_beams != nullptr) {
441	        const int global_batch_idx = beam_hyps.ite * beam_hyps.local_batch_size + batch_id;
442	        if (beam_hyps.num_beams[global_batch_idx] == 0 && tid == 0) {
443	            beam_hyps.min_normed_scores[global_batch_idx] = FLT_MAX;
444	        }
445	        else if (beam_hyps.num_beams[global_batch_idx] == k) {
446	            return;
447	        }
448	    }
449	
450	    TopK_2<T> partial;
451	
452	    // In some cases, we may encounter k finished sentences, but scores are bad. So, the max iteration
453	    // is 2*k here
454	    for (int ite = 0; ite < 2 * k; ite++) {
455	        partial.init();
456	#pragma unroll
457	        for (int i = tid; i < size; i += BLOCK_SIZE) {
458	            partial.insert(s_val[i], i);
459	        }
460	
461	        TopK_2<T> total = BlockReduce(temp_storage).Reduce(partial, reduce_topk_op_2<T>);
462	
463	        if (tid == 0) {
464	            if (beam_hyps.num_beams != nullptr
465	                && topk_tmp_id_buf[batch_id * size + total.p] % vocab_size == end_ids[batch_id]) {
466	                // if beam_token does not belong to top num_beams tokens, it should not be added. Refer from
467	                // https://github.com/huggingface/transformers/blob/v4.24.0/src/transformers/generation_beam_search.py#L257
468	                if (ite >= k) {
469	                    s_val[total.p] = -MAX_T_VAL;
470	                }
471	                else {
472	                    const int   global_batch_idx = beam_hyps.ite * beam_hyps.local_batch_size + batch_id;
473	                    const float normed_score =
474	                        apply_length_penalty(s_val[total.p], beam_hyps.step, beam_hyps.length_penalty);
475	                    const int num_beam = beam_hyps.num_beams[global_batch_idx];
476	                    int       beam_idx = num_beam;
477	                    // If there are beam_width finished sentences, check that the score of selected candidatet
478	                    // is higher than min_normed_score or not. If current score is better, replace worst one
479	                    // and update the min_normed_score.
480	                    if (num_beam == k) {
481	                        if (normed_score < beam_hyps.min_normed_scores[global_batch_idx]) {
482	                            // end the tracing and exist this for loop
483	                            selected_beams = k;
484	                            is_stop        = true;
485	                            break;
486	                        }
487	                        else {
488	                            // find the beam index which's score = min_normed_score, erase it.
489	                            for (int j = 0; j < k; j++) {
490	                                if (beam_hyps.normed_scores[global_batch_idx * k + j]
491	                                    == beam_hyps.min_normed_scores[global_batch_idx]) {
492	                                    beam_idx = j;
493	                                    beam_hyps.num_beams[global_batch_idx]--;
494	
495	                                    beam_hyps.min_normed_scores[global_batch_idx]     = FLT_MAX;
496	                                    beam_hyps.normed_scores[global_batch_idx * k + j] = normed_score;
497	                                    for (int l = 0; l < k; l++) {
498	                                        beam_hyps.min_normed_scores[global_batch_idx] =
499	                                            min(beam_hyps.min_normed_scores[global_batch_idx],
500	                                                beam_hyps.normed_scores[global_batch_idx * k + l]);
501	                                    }
502	                                    break;
503	                                }
504	                            }
505	                        }
506	                    }
507	                    const int tgt_id_offset = ((batch_id + beam_hyps.ite * beam_hyps.local_batch_size) * k + beam_idx)
508	                                              * (beam_hyps.max_seq_len);
509	                    beam_hyps.output_ids_tgt[tgt_id_offset + beam_hyps.step] = end_ids[batch_id];
510	
511	                    int prev_id = (topk_tmp_id_buf[batch_id * size + total.p] / vocab_size) % k;
512	                    for (int j = beam_hyps.step - 1; j >= 0; j--) {
513	                        const int src_idx = j * beam_hyps.batch_size * k
514	                                            + beam_hyps.ite * beam_hyps.local_batch_size * k + batch_id * k + prev_id;
515	
516	                        beam_hyps.output_ids_tgt[tgt_id_offset + j] = beam_hyps.output_ids_src[src_idx];
517	                        prev_id                                     = beam_hyps.parent_ids_src[src_idx];
518	                    }
519	                    const int tgt_beam_idx                       = global_batch_idx * k + beam_idx;
520	                    beam_hyps.sequence_lengths_tgt[tgt_beam_idx] = beam_hyps.step;
521	                    beam_hyps.normed_scores[tgt_beam_idx]        = normed_score;
522	                    beam_hyps.min_normed_scores[global_batch_idx] =
523	                        min(beam_hyps.min_normed_scores[global_batch_idx], beam_hyps.normed_scores[tgt_beam_idx]);
524	
525	                    s_val[total.p] = -MAX_T_VAL;
526	
527	                    beam_hyps.num_beams[global_batch_idx]++;
528	                }
529	            }
530	            else {
531	                s_id[selected_beams] = total.p;
532	                s_val[total.p]       = -MAX_T_VAL;
533	                selected_beams++;
534	            }
535	        }
536	        __syncthreads();
537	        if (selected_beams >= k) {
538	            break;
539	        }
540	    }
541	    if (tid < k && is_stop == false) {
542	        ids[batch_id * k + tid] = topk_tmp_id_buf[batch_id * size + s_id[tid]];
543	    }
544	}
545	
546	#define CASE_K_DIV(K, BLOCK_SIZE_1, BLOCK_SIZE_2)                                                                      \
547	    case K:                                                                                                            \
548	        beam_topK_kernel<T, K, BLOCK_SIZE_2><<<batch_size * beam_width, BLOCK_SIZE_2, 0, stream>>>(log_probs,          \
549	                                                                                                   topk_tmp_id_buf,    \
550	                                                                                                   topk_tmp_val_buf,   \
551	                                                                                                   finished,           \
552	                                                                                                   sequence_lengths,   \
553	                                                                                                   vocab_size,         \
554	                                                                                                   diversity_rate,     \
555	                                                                                                   length_penalty);    \
556	        if (K < 10)                                                                                                    \
557	            batch_topK_kernel<T, K, BLOCK_SIZE_1>                                                                      \
558	                <<<batch_size, BLOCK_SIZE_1, 0, stream>>>(topk_tmp_id_buf, topk_tmp_val_buf, ids);                     \
559	        else                                                                                                           \
560	            batch_topK_kernel_v2<T, K, 32><<<batch_size, 32, 0, stream>>>(topk_tmp_id_buf, topk_tmp_val_buf, ids);     \
561	        break;
562	
563	#define CASE_K(K, BLOCK_SIZE_1_, BLOCK_SIZE_2_, BLOCKS_PER_BEAM_)                                                      \
564	    case K:                                                                                                            \
565	        topk_stage_1_opt3<float, BLOCK_SIZE_1_, BLOCKS_PER_BEAM_>                                                      \
566	            <<<batch_size * K * BLOCKS_PER_BEAM_, BLOCK_SIZE_1_, 0, stream>>>(log_probs,                               \
567	                                                                              temp_log_probs,                          \
568	                                                                              topk_tmp_id_buf,                         \
569	                                                                              topk_tmp_val_buf,                        \
570	                                                                              finished,                                \
571	                                                                              sequence_lengths,                        \
572	                                                                              beam_width,                              \
573	                                                                              vocab_size,                              \
574	                                                                              length_penalty,                          \
575	                                                                              end_ids);                                \
576	        topk_stage_2_opt3<float, BLOCK_SIZE_2_, BLOCKS_PER_BEAM_>                                                      \
577	            <<<batch_size, BLOCK_SIZE_2_, K * sizeof(int), stream>>>(                                                  \
578	                topk_tmp_id_buf, topk_tmp_val_buf, ids, *beam_hyps, end_ids, vocab_size, beam_width);                  \
579	        sync_check_cuda_error();                                                                                       \
580	        break;
581	
582	template<typename T>
583	void invokeTopkBeamSearch(void*           workspace,
584	                          size_t&         workspace_size,
585	                          T*              log_probs,
586	                          int*            ids,
587	                          BeamHypotheses* beam_hyps,
588	                          const bool*     finished,
589	                          const int*      sequence_lengths,
590	                          const int       batch_size,
591	                          const int       beam_width,
592	                          const int       vocab_size_padded_,
593	                          const T         diversity_rate,
594	                          const float     length_penalty,
595	                          const int*      end_ids,
596	                          cudaStream_t    stream)
597	{
598	    FT_LOG_DEBUG("%s", __PRETTY_FUNCTION__);
599	    // log_probs: (batch, beam, vocab) cumulative log_probs of beams ending with a token.
600	    const int vocab_size = vocab_size_padded_;
601	    // Beam size should be less than or equal to vocab size.
602	    assert(beam_width <= vocab_size);
603	    // Beam search needs the sequence lengths of beams to apply length penalty.
604	    assert(length_penalty == 0.0f || sequence_lengths != nullptr);
605	    const int max_block_per_beam      = 8;
606	    int       temp_log_probs_buf_size = batch_size * beam_width * vocab_size;                       // type float
607	    int       topk_tmp_ids_buf_size   = batch_size * beam_width * beam_width * max_block_per_beam;  // type int
608	    int       topk_tmp_val_buf_size   = batch_size * beam_width * beam_width * max_block_per_beam;  // type float
609	
610	    // prevent memory misaligned address
611	    temp_log_probs_buf_size = (int)(ceil(temp_log_probs_buf_size / 4.)) * 4;
612	    topk_tmp_ids_buf_size   = (int)(ceil(topk_tmp_ids_buf_size / 4.)) * 4;
613	    topk_tmp_val_buf_size   = (int)(ceil(topk_tmp_val_buf_size / 4.)) * 4;
614	
615	    if (workspace == nullptr) {
616	        workspace_size = sizeof(float) * temp_log_probs_buf_size + sizeof(int) * topk_tmp_ids_buf_size
617	                         + sizeof(float) * topk_tmp_val_buf_size;
618	        return;
619	    }
620	    else {
621	        T*   temp_log_probs   = (T*)workspace;
622	        int* topk_tmp_id_buf  = (int*)(temp_log_probs + temp_log_probs_buf_size);
623	        T*   topk_tmp_val_buf = (T*)(topk_tmp_id_buf + topk_tmp_ids_buf_size);
624	        if (diversity_rate == 0.0f) {
625	            switch (beam_width) {
626	                CASE_K(1, 128, 128, 8);
627	                CASE_K(4, 128, 128, 8);
628	                CASE_K(10, 128, 128, 8);
629	                CASE_K(16, 128, 128, 5);
630	                CASE_K(32, 256, 128, 1);
631	                CASE_K(64, 256, 256, 1);
632	                default:
633	                    topk_stage_1_opt2_general<T, 128, 1>
634	                        <<<batch_size * beam_width * 1, 128, 0, stream>>>(log_probs,
635	                                                                          temp_log_probs,
636	                                                                          topk_tmp_id_buf,
637	                                                                          topk_tmp_val_buf,
638	                                                                          finished,
639	                                                                          sequence_lengths,
640	                                                                          beam_width,
641	                                                                          vocab_size,
642	                                                                          length_penalty);
643	                    topk_stage_2_opt2_general<T, 128, 1>
644	                        <<<batch_size,
645	                           128,
646	                           beam_width * beam_width * 1 * sizeof(float) + beam_width * sizeof(int),
647	                           stream>>>(
648	                            topk_tmp_id_buf, topk_tmp_val_buf, ids, *beam_hyps, end_ids, beam_width, vocab_size);
649	                    break;
650	            }
651	        }
652	        else {
653	            switch (beam_width) {
654	                CASE_K_DIV(1, 256, 256);
655	                CASE_K_DIV(4, 256, 256);
656	                CASE_K_DIV(16, 256, 64);
657	                CASE_K_DIV(32, 256, 64);
658	                CASE_K_DIV(64, 256, 64);
659	                default:
660	                    FT_CHECK_WITH_INFO(false, fmtstr("Topk kernel does not support beamwidth = %d \n", beam_width));
661	                    break;
662	            }
663	        }
664	        return;
665	    }
666	}
667	
668	#undef CASE_K
669	#undef CASE_K_DIV
670	
671	template void invokeTopkBeamSearch(void*           workspace,
672	                                   size_t&         workspace_size,
673	                                   float*          log_probs,
674	                                   int*            ids,
675	                                   BeamHypotheses* beam_hyps,
676	                                   const bool*     finished,
677	                                   const int*      sequence_lengths,
678	                                   const int       batch_size,
679	                                   const int       beam_width,
680	                                   const int       vocab_size_padded_,
681	                                   const float     diversity_rate,
682	                                   const float     length_penalty,
683	                                   const int*      end_ids,
684	                                   cudaStream_t    stream);
