686	template<typename T>
687	__global__ void tileEncoderResults(T*         tiled_output,
688	                                   int*       tiled_sequence_length,
689	                                   const T*   output,
690	                                   const int* sequence_length,
691	                                   const uint batch_size,
692	                                   const uint beam_width,
693	                                   const uint d_model)
694	{
695	    if (blockIdx.x == 0) {
696	        for (uint i = threadIdx.x; i < batch_size * beam_width; i += blockDim.x) {
697	            tiled_sequence_length[i] = sequence_length[i / beam_width];
698	        }
699	    }
700	
701	    int tgt_offset =
702	        blockIdx.x * gridDim.y * gridDim.z * d_model + blockIdx.y * gridDim.z * d_model + blockIdx.z * d_model;
703	    int src_offset = blockIdx.x * gridDim.z * d_model + blockIdx.z * d_model;
704	    for (uint i = threadIdx.x; i < d_model; i += blockDim.x) {
705	        tiled_output[i + tgt_offset] = output[i + src_offset];
706	    }
707	}
708	
709	template<typename T>
710	void invokeTileEncoderResults(T*           tiled_output,
711	                              int*         tiled_sequence_length,
712	                              const T*     output,
713	                              const int*   sequence_length,
714	                              const size_t batch_size,
715	                              const size_t beam_width,
716	                              const size_t mem_max_seq_len,
717	                              const size_t d_model,
718	                              cudaStream_t stream)
719	{
720	    // tiled_output: [batch_size, beam_width, mem_max_seq_len, d_model]
721	    // tiled_sequence_length: [batch_size, beam_width]
722	
723	    // output: [batch_size, mem_max_seq_len, d_model]
724	    // sequence_length [batch_size]
725	
726	    dim3 grid(batch_size, beam_width, mem_max_seq_len);
727	    bool is_half2 = (std::is_same<T, half>::value) && (d_model % 2 == 0);
728	
729	    if (is_half2) {
730	        using T2 = typename TypeConverter<T>::Type;  // fp16 to half2, bf16 to bf162
731	        dim3 block(min(512, (int)(d_model / 2)));
732	        tileEncoderResults<T2><<<grid, block, 0, stream>>>((T2*)tiled_output,
733	                                                           tiled_sequence_length,
734	                                                           (const T2*)output,
735	                                                           sequence_length,
736	                                                           batch_size,
737	                                                           beam_width,
738	                                                           d_model / 2);
739	    }
740	    else {
741	        dim3 block(min(512, (int)d_model));
742	        tileEncoderResults<T><<<grid, block, 0, stream>>>(
743	            tiled_output, tiled_sequence_length, output, sequence_length, batch_size, beam_width, d_model);
744	    }
745	}
