787	
788	__global__ void insertUnfinishedPath(BeamHypotheses beam_hyps,
789	                                     const bool*    finished,
790	                                     const float*   cum_log_probs,
791	                                     const int      batch_size,
792	                                     const int      beam_width)
793	{
794	    const int bid           = blockIdx.x;
795	    const int tgt_start_idx = beam_hyps.num_beams[bid];
796	    if (beam_hyps.is_done[bid]) {
797	        return;
798	    }
799	    for (int i = 0; i < beam_width; i++) {
800	        if (threadIdx.x == 0) {
801	            const int src_beam_idx = bid * beam_width + i;
802	            const int tgt_beam_idx = bid * beam_width * 2 + i + tgt_start_idx;
803	
804	            const int length = beam_hyps.sequence_lengths_src[src_beam_idx];
805	
806	            beam_hyps.output_ids_tgt[(tgt_beam_idx) * (beam_hyps.max_seq_len + 1) + length] =
807	                beam_hyps.output_ids_src[length * batch_size * beam_width + src_beam_idx];
808	            if (beam_hyps.log_probs != nullptr && beam_hyps.log_probs_src != nullptr) {
809	                beam_hyps.log_probs[(tgt_beam_idx) * (beam_hyps.max_seq_len + 1) + length] =
810	                    beam_hyps.log_probs_src[length * batch_size * beam_width + src_beam_idx];
811	            }
812	            int prev_id = beam_hyps.parent_ids_src[length * batch_size * beam_width + src_beam_idx];
813	            for (int j = length - 1; j >= 0; j--) {
814	                // output_ids_tgt need to use max_seq_len + 1 because its shape is
815	                // [bs, beam_width, max_seq_len + 1]
816	                beam_hyps.output_ids_tgt[(tgt_beam_idx) * (beam_hyps.max_seq_len + 1) + j] =
817	                    beam_hyps.output_ids_src[j * batch_size * beam_width + bid * beam_width + prev_id];
818	                if (beam_hyps.log_probs != nullptr && beam_hyps.log_probs_src != nullptr) {
819	                    beam_hyps.log_probs[(tgt_beam_idx) * (beam_hyps.max_seq_len + 1) + j] =
820	                        beam_hyps.log_probs_src[j * batch_size * beam_width + bid * beam_width + prev_id];
821	                }
822	                prev_id = beam_hyps.parent_ids_src[j * batch_size * beam_width + bid * beam_width + prev_id];
823	            }
824	            beam_hyps.sequence_lengths_tgt[tgt_beam_idx] = length;
825	
826	            beam_hyps.normed_scores[tgt_beam_idx] = apply_length_penalty(
827	                cum_log_probs[src_beam_idx], finished[src_beam_idx] ? length + 1 : length, beam_hyps.length_penalty);
828	            beam_hyps.cum_log_probs[tgt_beam_idx] = cum_log_probs[src_beam_idx];
829	
830	            beam_hyps.num_beams[bid]++;
831	        }
832	    }
833	}
834	
835	void invokeInsertUnfinishedPath(BeamHypotheses beam_hyps,
836	                                const bool*    finished,
837	                                const float*   cum_log_probs,
838	                                const int      batch_size,
839	                                const int      beam_width,
840	                                cudaStream_t   stream)
841	{
842	    insertUnfinishedPath<<<batch_size, 256, 0, stream>>>(beam_hyps, finished, cum_log_probs, batch_size, beam_width);
843	}
844	
845	}  // namespace fastertransformer
