24	template<typename T>
25	__global__ void add_bias_temperature(T*          logits,
26	                                     const T*    bias,
27	                                     const int   batch_size,
28	                                     const int   beam_width,
29	                                     const int   vocab_size,
30	                                     const int   vocab_size_padded,
31	                                     const float temperature)
32	{
33	    int tid  = threadIdx.x;
34	    int bid  = blockIdx.x;
35	    int bbid = blockIdx.y;
36	
37	    logits += bbid * vocab_size_padded;
38	
39	    const T MASK_VAL = (std::is_same<T, half>::value) ? -HALF_FLT_MAX : -FLT_MAX;
40	    const T inv_temp = static_cast<T>(1.0f / (temperature + 1e-6f));
41	    for (int i = tid + bid * blockDim.x; i < vocab_size_padded; i += blockDim.x * gridDim.x) {
42	        if (i < vocab_size) {
43	            T bias_val = bias == nullptr ? (T)(0.0f) : bias[i];
44	            logits[i]  = (logits[i] + bias_val) * inv_temp;
45	        }
46	        else {
47	            logits[i] = MASK_VAL;
48	        }
49	    }
50	}
