52	template<>
53	__global__ void add_bias_temperature(half2*       logits,
54	                                     const half2* bias,
55	                                     const int    batch_size,
56	                                     const int    beam_width,
57	                                     const int    vocab_size,
58	                                     const int    vocab_size_padded,
59	                                     const float  temperature)
60	{
61	    assert(vocab_size % 2 == 0);
62	    assert(vocab_size_padded % 2 == 0);
63	
64	    const int tid  = threadIdx.x;
65	    const int bid  = blockIdx.x;
66	    const int bbid = blockIdx.y;
67	
68	    const half2 mask_val = __float2half2_rn(-HALF_FLT_MAX);
69	    const half2 inv_temp = __float2half2_rn(1.0f / (temperature + 1e-6f));
70	
71	    const int half_vocab_size        = vocab_size / 2;
72	    const int half_vocab_size_padded = vocab_size_padded / 2;
73	
74	    logits += bbid * half_vocab_size_padded;
75	    for (int index = tid + bid * blockDim.x; index < half_vocab_size_padded; index += blockDim.x * gridDim.x) {
76	        int   vocab_idx = index % half_vocab_size_padded;
77	        half2 logit     = vocab_idx < half_vocab_size ? __ldg(&logits[index]) : mask_val;
78	        if (vocab_idx < half_vocab_size) {
79	            if (bias != nullptr) {
80	                logit = __hadd2(logit, bias[vocab_idx]);
81	            }
82	            logit = __hmul2(logit, inv_temp);
83	        }
84	        logits[index] = logit;
85	    }
86	}
