88	template<typename T, bool IS_ADDITIVE>
89	__global__ void apply_repetition_penalty(T*          logits,
90	                                         const int   batch_size,
91	                                         const int   beam_width,
92	                                         const int   vocab_size,
93	                                         const int   vocab_size_padded,
