100	                                         const float repetition_penalty)
101	{
102	    assert(step > 0);
103	
104	    const int tid      = threadIdx.x;
105	    const int bbid     = blockIdx.x;
106	    const int batch_id = bbid / beam_width;
107	    const int bbsize   = batch_size * beam_width;
108	
109	    logits += bbid * vocab_size_padded;
110	    extern __shared__ char sbuf[];
111	    T*                     penalty_logits = reinterpret_cast<T*>(sbuf);
112	    // prevent misaligment when sizeof(T) = 2
113	    int*      penalty_indices = reinterpret_cast<int*>(sbuf + (sizeof(T) * step + 31) / 32 * 32);
114	    const int input_length    = (input_lengths != nullptr) ? input_lengths[bbid] : max_input_length;
115	    if (tid == 0) {
116	        T   repet_penalty         = static_cast<T>(repetition_penalty);
117	        int prev_id               = current_ids[bbid];
118	        T   prev_logit            = logits[prev_id];
119	        penalty_indices[step - 1] = prev_id;
120	
121	        if (IS_ADDITIVE) {
122	            penalty_logits[step - 1] = prev_logit - repet_penalty;
123	        }
124	        else {
125	            penalty_logits[step - 1] = prev_logit > T(0) ? prev_logit / repet_penalty : prev_logit * repet_penalty;
126	        }
127	        if (step > 1) {
128	            int parent_beam = bbid % beam_width;
129	            for (int i = step - 2; i >= 0; --i) {
130	                // Skip the padded tokens.
131	                if (i >= input_length && i < max_input_length) {
132	                    continue;
133	                }
134	                parent_beam        = parent_ids[i * bbsize + batch_id * beam_width + parent_beam];
135	                prev_id            = previous_ids[i * bbsize + batch_id * beam_width + parent_beam];
136	                prev_logit         = logits[prev_id];
137	                penalty_indices[i] = prev_id;
138	                if (IS_ADDITIVE) {
139	                    penalty_logits[i] = prev_logit - repet_penalty;
140	                }
141	                else {
142	                    penalty_logits[i] = prev_logit > T(0) ? prev_logit / repet_penalty : prev_logit * repet_penalty;
143	                }
144	            }
145	        }
146	    }
147	    __syncthreads();
148	    for (int i = tid; i < step; i += blockDim.x) {
149	        if (i >= input_length && i < max_input_length) {
